// Accept input from the webhook (fields under body) or the manual test (direct fields)
const src = $json.body ?? $json;
return [{
  json: {
    client_name: src.client_name ?? '',
    phone: src.phone ?? '',
    channel: src.channel ?? 'whatsapp',
    crm_lead_id: src.crm_lead_id ?? '',
    service_hint: src.service_hint ?? '',
    message: src.message ?? ''
  }
}];

// Condensed system prompt. The full authoritative version lives in
// bp-specialized-team/prompts/badr-sales-bd.md — keep the two in sync.
const intake = $('Normalize Input').first().json;

const catalogItems = $input.all()
  .map(i => i.json)
  .filter(j => j && (j.name || j.properties))
  .slice(0, 25);
const catalogText = catalogItems.length
  ? JSON.stringify(catalogItems)
  : 'CATALOG_UNAVAILABLE — do not state or estimate any price.';

const systemPrompt = [
  'You are Badr, the Sales & Business Development Agent for Business Partner (بزنس بارتنر سلوشنز) in Saudi Arabia.',
  'You handle pricing requests, quotations, proposals, packages, and commercial scope for exactly four services: Company Formation (تأسيس الشركات), HR Solutions (حلول الموارد البشرية), Government Relations / GRO (العلاقات الحكومية), Premium Residency (الإقامة المميزة).',
  'Rules:',
  '- Reply in the client\'s language (default Arabic), professional and brief.',
  '- Ask at most ONE qualification question per message.',
  '- Use approved catalog prices only. If the catalog is unavailable or the price is not visible, never invent or estimate a price.',
  '- Never give discounts, contracts, invoices, or payment links. Never promise government outcomes, fees, or timelines.',
  '- Never request passwords, OTP, credentials, sensitive identity data, or operational documents before contract stage.',
  '- The final proposal is always reviewed by the team before sending — say so when a proposal is requested.',
  '- Legal/eligibility questions, discount requests, human-contact requests: give a safe holding reply and note the team will follow up.',
  'When, and only when, the core information is complete (service + new/existing company + scope + one-time vs monthly), end your reply with the exact marker [PROPOSAL_READY] on its own line.',
  '',
  'Approved services catalog (JSON):',
  catalogText
].join('\n');

const userContent = [
  `Client name: ${intake.client_name || 'unknown'}`,
  `Channel: ${intake.channel}`,
  `Service hint: ${intake.service_hint || 'none'}`,
  `Message: ${intake.message}`
].join('\n');

return [{
  json: {
    anthropic_body: {
      model: 'claude-sonnet-5',
      max_tokens: 1024,
      system: systemPrompt,
      messages: [{ role: 'user', content: userContent }]
    }
  }
}];

// Resilience (Compliance Agent V1 pattern): if the engine fails, use the approved
// TEAM-003 safe reply and keep the flow alive. The alert/reply itself is the product.
const item = $input.first().json;
const fallback = 'نقدر نجهز لك عرض سعر واضح بعد تثبيت نطاق الخدمة.\nحتى يكون العرض دقيق: هل العرض المطلوب لتأسيس الشركات، حلول الموارد البشرية، العلاقات الحكومية، أم الإقامة المميزة؟';

let text = '';
if (item && Array.isArray(item.content) && item.content[0] && item.content[0].text) {
  text = item.content[0].text;
}
const engine_fallback = !text;
if (engine_fallback) text = fallback;

const proposal_ready = !engine_fallback && text.includes('[PROPOSAL_READY]');
const reply = text.replace('[PROPOSAL_READY]', '').trim();

const intake = $('Normalize Input').first().json;
return [{ json: { ...intake, reply, proposal_ready, engine_fallback } }];

// SKELETON PLACEHOLDER — replace with a Notion 'update databasePage' node once the
// CRM database property names are mapped. Target state per TEAM-003/TEAM-005:
//   Assigned Agent = Badr / Sales
//   Lead Stage     = Proposal / Under Review
//   Human Required = YES
//   Notes          = service, scope, and the client's last request
const j = $('Parse Reply + Safe Fallback').first().json;
return [{ json: { ...j, crm_update: { assigned_agent: 'Badr / Sales', lead_stage: 'Proposal / Under Review', human_required: true } } }];
